using Microsoft.AspNetCore.Mvc;
using System.Linq;
using YourNamespace.Models; // Adjust this to match the location of your models

public class ProductController : Controller
{
    private readonly ApplicationDbContext _context;

    public ProductController(ApplicationDbContext context)
    {
        _context = context;
    }

    public IActionResult DisplayReviews(int id)
    {
        var product = _context.Products.Find(id);
        if (product == null)
        {
            return NotFound();
        }

        var reviews = _context.Reviews.Where(r => r.ProductId == id).ToList();
        ViewData["ProductName"] = product.Name;

        foreach (var review in reviews)
        {
            review.FormattedReviewText = FormatText(review.ReviewText); // Assuming you have a method for formatting the text
            review.ReviewText = null; // To avoid storing and returning original, unformatted text
        }

        return View(reviews);
    }

    private string FormatText(string text)
    {
        // Implement your formatting logic here (e.g., replacing certain tags with HTML entities)
        // For example:
        text = text.Replace("**", "<strong>").Replace("_", "<em>");
        return text;
    }
}